/* styles.css */
body {
  font-family: system-ui, sans-serif;
  line-height: 1.6;
  margin: 0;
  color: #1e293b;
}

h1 {
  color: #04aa6d;
}

nav a {
  text-decoration: none;
  color: #04aa6d;
}

.card {
  padding: 1rem;
  border-radius: 8px;
}

.btn:hover {
  background: #059862;
}

li:nth-child(odd) {
  background: #f8fafc;
}

*,
*::before,
*::after {
  box-sizing: border-box;
}

.card {
  width: 280px;
  padding: 1.25rem;
  border: 2px solid #e2e8f0;
  margin: 1rem auto;
  background: #fff;
}

:root {
  --brand: #04aa6d;
  --text: #1e293b;
}

.hero {
  color: #fff;
  background: linear-gradient(135deg, var(--brand), #059862);
}

.badge {
  background: hsl(160 84% 39% / 0.15);
  color: var(--brand);
}

.nav {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 1rem;
  padding: 0.75rem 1.5rem;
}

.nav-links {
  display: flex;
  gap: 1.25rem;
  list-style: none;
  margin: 0;
  padding: 0;
}

.layout {
  display: grid;
  grid-template-columns: 240px 1fr;
  grid-template-rows: auto 1fr auto;
  grid-template-areas:
    "header header"
    "sidebar main"
    "footer footer";
  min-height: 100vh;
  gap: 1rem;
}

.main { grid-area: main; }

.btn {
  transition: transform 0.2s ease, background 0.2s ease;
}

.btn:hover {
  transform: translateY(-2px);
}

@keyframes fade-in {
  from { opacity: 0; transform: translateY(8px); }
  to { opacity: 1; transform: translateY(0); }
}

.card {
  animation: fade-in 0.5s ease forwards;
}

.cards {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(260px, 1fr));
  gap: 1.5rem;
  padding: 1rem;
}

@media (min-width: 768px) {
  .cards { padding: 2rem; }
}

img {
  max-width: 100%;
  height: auto;
}
